1	{% if section is not defined %}{% set section = sections[step] %}{% endif %}
2	<form hx-post="{{ url_for('assessments.wizard_step', step=step + 1) }}" hx-target="#assessment-content" hx-swap="innerHTML">
3	    <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
4	    <input type="hidden" name="visit_id" value="{{ visit_id or '' }}">
5	    <input type="hidden" name="request_token" value="{{ request_token }}">
6	
7	    <h3>{{ section.title }}</h3>
8	    <p class="field-hint">{{ section.description }}</p>
9	
10	    {% for q in section.questions %}
11	    <div class="form-group" style="margin-top:1rem;">
12	        <label>{{ q.text }}</label>
13	
14	        {% if q.type == 'scale_0_3' %}
15	        <div style="display:flex; gap:1rem; flex-wrap:wrap; margin-top:0.25rem;">
16	            {% for val, label in [(0, 'Not at all'), (1, 'Several days'), (2, 'More than half'), (3, 'Nearly every day')] %}
17	            <label style="display:flex; align-items:center; gap:0.25rem; cursor:pointer;">
18	                <input type="radio" name="{{ q.id }}" value="{{ val }}" required
19	                       {% if saved_answers.get(q.id)|string == val|string %}checked{% endif %}>
20	                {{ label }} ({{ val }})
21	            </label>
22	            {% endfor %}
23	        </div>
24	
25	        {% elif q.type == 'yes_no' %}
26	        <div style="display:flex; gap:1rem; margin-top:0.25rem;">
27	            {% for val, label in [('yes', 'Yes'), ('no', 'No')] %}
28	            <label style="display:flex; align-items:center; gap:0.25rem; cursor:pointer;">
29	                <input type="radio" name="{{ q.id }}" value="{{ val }}" required
30	                       {% if saved_answers.get(q.id) == val %}checked{% endif %}>
31	                {{ label }}
32	            </label>
33	            {% endfor %}
34	        </div>
35	
36	        {% elif q.type == 'select' %}
37	        <select name="{{ q.id }}" class="form-control" required style="max-width:300px;">
38	            <option value="">-- Select --</option>
39	            {% for opt in q.options %}
40	            <option value="{{ opt }}" {% if saved_answers.get(q.id) == opt %}selected{% endif %}>
41	                {{ opt | replace('_', ' ') | title }}
42	            </option>
43	            {% endfor %}
44	        </select>
45	        {% endif %}
46	    </div>
47	    {% endfor %}
48	
49	    <!-- Carry forward saved answers as hidden fields -->
50	    {% for key, val in saved_answers.items() %}
51	    <input type="hidden" name="{{ key }}" value="{{ val }}">
52	    {% endfor %}
53	
54	    <div style="display:flex; gap:1rem; margin-top:1.5rem;">
55	        <button type="submit" class="btn btn-primary">
56	            {% if step + 1 >= total_steps %}Review{% else %}Next{% endif %}
57	        </button>
58	    </div>
59	</form>
